//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, TCAdmin.Web.Shared.dll, System.Net.Http.dll, System.IO.Compression.dll, System.IO.Compression.ZipFile.dll
using System;
using System.IO;
using System.IO.Compression;
using System.Net.Http;
using System.Threading.Tasks;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Downloads windows-kill.exe (used by the BeforeServiceStopped Ctrl+C script) into the service root.
const string url = "https://github.com/ElyDotDev/windows-kill/releases/download/1.1.4/windows-kill_1.1.4_release.zip";
const string entryPath = "windows-kill_x64_1.1.4_lib_release/windows-kill.exe";

string targetDir = ThisService.RootDirectory;
Directory.CreateDirectory(targetDir);

string zipPath = Path.Combine(targetDir, "windows-kill_1.1.4_release.zip");
string targetExe = Path.Combine(targetDir, "windows-kill.exe");

ScriptConsole.WriteLine($"Downloading {url}");
using (var http = new HttpClient())
{
    byte[] data = await http.GetByteArrayAsync(url, ThisCancellationToken);
    await File.WriteAllBytesAsync(zipPath, data, ThisCancellationToken);
}
ScriptConsole.WriteLine($"Downloaded to {zipPath}");

using (ZipArchive archive = ZipFile.OpenRead(zipPath))
{
    ZipArchiveEntry entry = archive.GetEntry(entryPath);
    if (entry == null)
        throw new Exception($"Entry '{entryPath}' not found in the archive.");
    entry.ExtractToFile(targetExe, overwrite: true);
}
ScriptConsole.WriteLine($"Extracted windows-kill.exe to {targetExe}");

try
{
    File.Delete(zipPath);
    ScriptConsole.WriteLine($"Deleted archive {zipPath}");
}
catch (Exception ex)
{
    ScriptConsole.WriteLine($"Warning: could not delete zip file: {ex.Message}");
}

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, TCAdmin.Web.Shared.dll, System.Diagnostics.Process.dll
using System;
using System.Diagnostics;
using System.IO;
using System.Threading;
using System.Threading.Tasks;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Graceful SCUM stop: send Ctrl+C (SIGINT) to the running game process via windows-kill.exe,
// then wait up to 60s for it to exit before TCAdmin proceeds with its own stop.
int? pid = ThisService.ProcessId;
if (pid == null || pid <= 0)
{
    ScriptConsole.WriteLine("No running process id for this service; nothing to stop.");
    return;
}

string killExe = Path.Combine(ThisService.RootDirectory, "windows-kill.exe");
if (!File.Exists(killExe))
{
    ScriptConsole.WriteLine($"windows-kill.exe not found at {killExe}; skipping graceful Ctrl+C stop.");
    return;
}

ScriptConsole.WriteLine($"Sending SIGINT (Ctrl+C) to process {pid} via windows-kill.exe");
var psi = new ProcessStartInfo
{
    FileName = killExe,
    Arguments = $"-SIGINT {pid}",
    WorkingDirectory = ThisService.RootDirectory,
    UseShellExecute = false,
    CreateNoWindow = true,
    RedirectStandardOutput = true,
    RedirectStandardError = true
};

try
{
    using var killer = Process.Start(psi);
    if (killer != null)
        await killer.WaitForExitAsync(ThisCancellationToken);
}
catch (Exception ex)
{
    ScriptConsole.WriteLine($"Failed to run windows-kill.exe: {ex.Message}");
    return;
}

const int maxChecks = 60;
for (int count = 1; count <= maxChecks; count++)
{
    bool running;
    try
    {
        using var proc = Process.GetProcessById(pid.Value);
        running = !proc.HasExited;
    }
    catch (ArgumentException)
    {
        running = false; // process no longer exists
    }

    if (!running)
    {
        ScriptConsole.WriteLine($"Process {pid} has exited after {count} second(s).");
        return;
    }

    await Task.Delay(TimeSpan.FromSeconds(1), ThisCancellationToken);
}

ScriptConsole.WriteLine($"WARNING: process {pid} did not exit within {maxChecks} seconds.");

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, TCAdmin.Web.Shared.dll
using System;
using System.IO;
using System.Linq;
using System.Text;
using TCAdmin.SDK.Hubs.Models.GameQuery;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// CustomQueryProtocol: V3 deserializes the ReturnValue into a GameQueryResponse (V2 returned qstat XML).
// The query subsystem injects the resolved query Address/Port; fall back to the service's own.
string address = Variables.Parse<string>("Address", ThisService.IPAddress);
int queryPort = Variables.Parse<int>("Port", ThisService.QueryPort);
string gameType = "SCUM";
string mapName = ThisService.Variables.Parse<string>("Map", "SCUM") ?? "SCUM";

// 1) Player count from the most recent login_*.log (joins minus leaves).
string rootDir = ThisService.RootDirectory;
string logDir = Path.Combine(rootDir, "SCUM", "Saved", "SaveFiles", "Logs");
int joins = 0;
int leaves = 0;
try
{
    if (Directory.Exists(logDir))
    {
        string latest = Directory.GetFiles(logDir, "login_*.log")
            .OrderByDescending(f => f)
            .FirstOrDefault();
        if (latest != null)
        {
            // SCUM writes these logs as UTF-16LE (with BOM); ReadAllLines honours the BOM.
            foreach (string line in File.ReadAllLines(latest, Encoding.Unicode))
            {
                string l = line.ToLowerInvariant();
                if (l.Contains("logged in at")) joins++;
                else if (l.Contains("logged out at")) leaves++;
            }
        }
    }
}
catch (Exception ex)
{
    ScriptConsole.WriteLine($"player query: could not read login logs: {ex.Message}");
}

int numPlayers = Math.Max(0, joins - leaves);

// 2) ServerName + MaxPlayers from ServerSettings.ini.
string iniPath = Path.Combine(rootDir, "SCUM", "Saved", "Config", "WindowsServer", "ServerSettings.ini");
string serverName = "SCUM Server";
int maxPlayers = ThisService.Slots;
if (File.Exists(iniPath))
{
    try
    {
        foreach (string raw in File.ReadAllLines(iniPath))
        {
            string line = raw.Trim();
            if (line.StartsWith("scum.ServerName=", StringComparison.OrdinalIgnoreCase))
                serverName = line.Substring(line.IndexOf('=') + 1);
            else if (line.StartsWith("scum.MaxPlayers=", StringComparison.OrdinalIgnoreCase)
                     && int.TryParse(line.Substring(line.IndexOf('=') + 1).Trim(), out int mp))
                maxPlayers = mp;
        }
    }
    catch (Exception ex)
    {
        ScriptConsole.WriteLine($"player query: could not read ServerSettings.ini: {ex.Message}");
    }
}

Globals.ReturnValue = new GameQueryResponse
{
    Status = "online",
    Hostname = $"{address}:{queryPort}",
    Name = serverName,
    GameType = gameType,
    Map = mapName,
    NumPlayers = numPlayers,
    MaxPlayers = maxPlayers
};
